import * as cheerio from "cheerio";
import type { FeedConfig, FeedItem } from "../../types.js";

function parseDate(dateStr: string): string {
  // Dates are like "April 30, 2026" or "May 1, 2026"
  const date = new Date(dateStr);
  if (!isNaN(date.getTime())) {
    return date.toISOString();
  }
  return new Date().toISOString();
}

export async function fetchFeed(config: FeedConfig): Promise<FeedItem[]> {
  // 1. Fetch the listing page
  const res = await fetch(config.url);
  const html = await res.text();
  const $ = cheerio.load(html);

  // 2. Parse items from the list view (blog_cms_list)
  // Deduplicate by tracking seen URLs
  const seenUrls = new Set<string>();
  const items: Array<{ title: string; url: string; dateStr: string }> = [];

  // Use blog_cms_list items (cleaner structure with proper dates)
  $(`.blog_cms_list .blog_cms_item`).each((_i, el) => {
    const linkEl = $(el).find("a.clickable_link");
    const href = linkEl.attr("href");
    if (!href) return;
    
    const fullUrl = href.startsWith("http") ? href : `https://claude.com${href}`;
    if (seenUrls.has(fullUrl)) return;
    seenUrls.add(fullUrl);

    const title = $(el).find("h3.card_blog_list_title").text().trim();
    const dateStr = $(el).find('div[fs-list-field="date"]').text().trim();

    if (!title || !fullUrl) return;

    items.push({ title, url: fullUrl, dateStr });
  });

  // If list view had no items, try the grid view as fallback
  if (items.length === 0) {
    $(`.blog_cms_grid .blog_cms_item`).each((_i, el) => {
      const linkEl = $(el).find("a.clickable_link");
      const href = linkEl.attr("href");
      if (!href) return;
      
      const fullUrl = href.startsWith("http") ? href : `https://claude.com${href}`;
      if (seenUrls.has(fullUrl)) return;
      seenUrls.add(fullUrl);

      const title = $(el).find(".card_blog_title").text().trim();
      const dateStr = $(el).find(".u-text-style-caption.u-foreground-tertiary").first().text().trim();

      if (!title || !fullUrl) return;

      items.push({ title, url: fullUrl, dateStr });
    });
  }

  // 3. Fetch all detail pages in parallel
  const detailResults = await Promise.all(
    items.map(async (item) => {
      try {
        const res = await fetch(item.url);
        const detailHtml = await res.text();
        const $detail = cheerio.load(detailHtml);

        // Extract first og:image (skip generic fallback)
        const ogImage = $detail('meta[property="og:image"]').first().attr("content") || "";

        // Extract full content HTML
        const contentBody = $detail(".u-rich-text-blog").first();
        const contentHtml = contentBody.length > 0 ? contentBody.html() || "" : "";

        // Resolve relative image URL
        let imageUrl = ogImage;
        if (imageUrl && !imageUrl.startsWith("http")) {
          try {
            imageUrl = new URL(imageUrl, item.url).href;
          } catch {
            imageUrl = "";
          }
        }

        return { imageUrl, contentHtml };
      } catch {
        // Graceful degradation: return empty optional fields
        return { imageUrl: "", contentHtml: "" };
      }
    })
  );

  // 4. Build final FeedItem array
  const feedItems: FeedItem[] = items.map((item, i) => {
    const detail = detailResults[i];
    const feedItem: FeedItem = {
      id: item.url,
      title: item.title,
      url: item.url,
      publishedAt: parseDate(item.dateStr),
      source: config.slug,
    };

    if (detail.contentHtml) {
      feedItem.contentHtml = detail.contentHtml;
    }

    if (detail.imageUrl) {
      feedItem.imageUrl = detail.imageUrl;
    }

    return feedItem;
  });

  return feedItems;
}
